*, *::before, *::after { margin: 0; padding: 0; box-sizing: border-box; }
    body {
      font-family: 'Manrope', system-ui, sans-serif;
      background: hsl(var(--bg-page, 20 23% 97%));
    }

    /* ── BLOCK: fast-loading-speed (unique styles only) ── */

    .block-fast-loading-speed {
      background: hsl(206 100% 92%);
      border-radius: 32px;
      padding: var(--spacing-5xl, 64px) var(--spacing-3xl, 40px);
      display: flex;
      flex-direction: column;
      align-items: center;
      gap: var(--spacing-2xl);
      width: 615px;
      color: hsl(231 68% 29%);
    }

    .block-fast-loading-speed .heading {
      font-size: var(--h2-font-size, 42px);
      font-weight: var(--font-weight-medium, 500);
      line-height: var(--h2-line-height, 46px);
      text-align: center;
      max-width: 475px;
    }

    .block-fast-loading-speed .gauge-wrap {
      position: relative;
      width: 220px;
      height: 220px;
    }
    .block-fast-loading-speed .gauge-svg {
      width: 100%;
      height: 100%;
      overflow: visible;
    }

    .block-fast-loading-speed .gauge-score {
      position: absolute;
      inset: 0;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 60px;
      font-weight: var(--font-weight-semibold, 600);
      line-height: 1;
      letter-spacing: -3px;
      opacity: 0;
    }

    .block-fast-loading-speed .bottom-info {
      display: flex;
      flex-direction: column;
      align-items: center;
      text-align: center;
    }
    .block-fast-loading-speed .score-label {
      font-size: var(--h4-font-size, 26px);
      font-weight: var(--font-weight-regular, 400);
      line-height: var(--h4-line-height, 34px);
    }
    .block-fast-loading-speed .score-source {
      font-size: var(--text-sm-font-size, 15px);
      line-height: var(--text-sm-line-height, 20px);
    }

    /* ── Gauge-specific animations ── */
    @keyframes cyanDraw {
      from { stroke-dashoffset: 540; }
      to { stroke-dashoffset: 0; }
    }
    .block-fast-loading-speed .ring-fill-animated {
      stroke-dashoffset: 540;
    }
    .block-fast-loading-speed .ring-fill-animated.animate {
      animation: cyanDraw 1.4s cubic-bezier(0.16, 1, 0.3, 1) forwards;
    }
@container slot (max-width: 768px) {
