const block = document.querySelector('.block-fast-loading-speed');
    const io = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting) { e.target.classList.add('visible'); io.unobserve(e.target); } });
    }, { threshold: 0.15 });
    block.querySelectorAll('.reveal, .reveal-scale').forEach(el => io.observe(el));

    const gaugeWrap = block.querySelector('.gauge-wrap');
    const eraser = block.querySelector('#whiteRingEraser');
    const gaugeIO = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          block.querySelector('.ring-fill-animated').classList.add('animate');
          eraser.animate([
            { strokeDasharray: '597 0', strokeDashoffset: 0 },
            { strokeDasharray: '60 537', strokeDashoffset: -537 }
          ], { duration: 1400, easing: 'cubic-bezier(0.16, 1, 0.3, 1)', fill: 'forwards' });

          const scoreNum = block.querySelector('#scoreNum');
          const scorePlus = block.querySelector('#scorePlus');
          let count = 65;
          scoreNum.textContent = count;
          scoreNum.parentElement.style.opacity = '1';
          const counter = setInterval(() => {
            count++;
            scoreNum.textContent = count;
            if (count >= 90) { clearInterval(counter); scorePlus.style.opacity = '1'; scorePlus.style.transition = 'opacity 0.3s ease'; }
          }, 40);

          gaugeIO.unobserve(e.target);
        }
      });
    }, { threshold: 0.3 });
    gaugeIO.observe(gaugeWrap);
